import type { ExtensionAPI, ExtensionCommandContext } from "@earendil-works/pi-coding-agent";
import { DynamicBorder } from "@earendil-works/pi-coding-agent";
import type { Model } from "@earendil-works/pi-ai";
import {
  Container,
  Text,
  SelectList,
  type SelectItem,
} from "@earendil-works/pi-tui";

const PROVIDER = "opencode-go";

// ─── Curated suggested uses ────────────────────────────────────────────────
// Hand-written per model. Falls back to `heuristicUse()` for any new/unknown
// model that gets added to opencode-go in the future.
const SUGGESTED_USE: Record<string, string> = {
    "minimax-m3":
        "default workhorse — cheap Anthropic-style reasoning, vision + 512K ctx (3× usage)",
    "deepseek-v4-flash":
        "budget text reasoning — 1M ctx for pennies, DeepSeek thinking",
    "mimo-v2.5":
        "budget vision + reasoning — same price as DeepSeek Flash but adds image input",
    "minimax-m2.7":
        "mid-tier general purpose — cheaper than GLM, text-only",
    "qwen3.7-plus":
        "vision via Anthropic API — 1M ctx, prompt caching supported",
    "qwen3.6-plus":
        "long-context multimodal — 1M ctx, vision, prompt caching",
    "kimi-k2.6":
        "vision + reasoning — Moonshot Kimi, multimodal generalist",
    "kimi-k2.7-code":
        "coding & agentic — vision in, 262K output for long generations",
    "glm-5.1":
        "multilingual GLM — 200K ctx, mid-tier pricing",
    "glm-5.2":
        "long-context GLM — 1M ctx at mid-tier price",
    "deepseek-v4-pro":
        "DeepSeek Pro — 1M ctx, hard reasoning at premium price",
    "mimo-v2.5-pro":
        "MiMo Pro — 1M ctx, premium reasoning, vision-capable provider",
    "qwen3.7-max":
        "frontier — most expensive, save for the hardest problems",
};

// ─── Heuristic fallback for unknown models ──────────────────────────────────
type ModelRow = {
    id: string;
    name: string;
    cost: { input: number; output: number; cacheRead: number; cacheWrite: number };
    contextWindow: number;
    maxTokens: number;
    reasoning: boolean;
    input: ("text" | "image")[];
};

function heuristicUse(m: ModelRow): string {
    const tags: string[] = [];
    if (m.id.includes("code") || m.id.includes("coder")) tags.push("coding");
    if (m.input.includes("image")) tags.push("vision");
    if (m.reasoning) tags.push("reasoning");
    if (m.contextWindow >= 1_000_000) tags.push("1M ctx");
    else if (m.contextWindow >= 500_000) tags.push("long ctx");

    let tier: string;
    if (m.cost.input <= 0.15) tier = "budget";
    else if (m.cost.input >= 1.5) tier = "premium";
    else tier = "mid-tier";

    return tags.length === 0 ? `${tier} general purpose` : `${tier} ${tags.join(" + ")}`;
}

// ─── Formatting helpers ────────────────────────────────────────────────────
function fmtPrice(n: number): string {
    if (n === 0) return "—";
    if (n < 0.01) return `$${n.toFixed(4)}`;
    if (n < 1) return `$${n.toFixed(2)}`;
    return `$${n.toFixed(2)}`;
}

function fmtCtx(n: number): string {
    if (n >= 1_000_000) {
        const m = n / 1_000_000;
        return `${m % 1 === 0 ? m.toFixed(0) : m.toFixed(1)}M`;
    }
    if (n >= 1_000) return `${Math.round(n / 1_000)}K`;
    return String(n);
}

function buildRow(m: ModelRow): { value: string; label: string; description: string } {
    const use = SUGGESTED_USE[m.id] ?? heuristicUse(m);
    const vision = m.input.includes("image") ? "👁 " : "  ";
    const reason = m.reasoning ? "🧠" : "  ";
    const inP = fmtPrice(m.cost.input);
    const outP = fmtPrice(m.cost.output);
    const ctx = fmtCtx(m.contextWindow);
    const max = fmtCtx(m.maxTokens);
    // Label is left-aligned for scanning; description is the "why" text.
    const label = `in ${inP.padStart(6)} · out ${outP.padStart(6)} · ${ctx.padStart(5)} ctx / ${max.padStart(5)} out  ${vision}${reason}  ${m.name}`;
    return { value: `${PROVIDER}/${m.id}`, label, description: use };
}

function modelToRow(m: Model<any>): ModelRow {
    return {
        id: m.id,
        name: m.name,
        cost: m.cost,
        contextWindow: m.contextWindow,
        maxTokens: m.maxTokens,
        reasoning: m.reasoning,
        input: m.input,
    };
}

// ─── Extension ─────────────────────────────────────────────────────────────
export default function (pi: ExtensionAPI) {
    pi.registerCommand("compareModels", {
        description: "List opencode-go models sorted by price with a suggested use for each",
        handler: async (_args: string, ctx: ExtensionCommandContext) => {
            const all = ctx.modelRegistry.getAll();
            const models = all
                .filter((m) => m.provider === PROVIDER)
                .map(modelToRow)
                .sort((a, b) => a.cost.input - b.cost.input);

            if (models.length === 0) {
                ctx.ui.notify(`No ${PROVIDER} models found in registry.`, "warning");
                return;
            }

            const header = {
                value: "__header__",
                label: `${models.length} ${PROVIDER} models · sorted cheapest input first`,
                description: "Enter = switch to that model · Esc = cancel",
            };
            const items = [header, ...models.map(buildRow)];

            const choice = await ctx.ui.custom<string | null>((tui, theme, _kb, done) => {
                const container = new Container();
                container.addChild(new DynamicBorder((str: string) => theme.fg("accent", str)));
                container.addChild(new Text(theme.fg("accent", theme.bold(`${PROVIDER} models · sorted cheapest input first`))));
                const selectList = new SelectList(items, Math.min(items.length, 12), {
                    selectedPrefix: (text: string) => theme.fg("accent", text),
                    selectedText: (text: string) => theme.fg("accent", text),
                    description: (text: string) => theme.fg("muted", text),
                    scrollInfo: (text: string) => theme.fg("dim", text),
                    noMatch: (text: string) => theme.fg("warning", text),
                });
                selectList.onSelect = (item) => done(item.value === "__header__" ? null : item.value);
                selectList.onCancel = () => done(null);
                container.addChild(selectList);
                container.addChild(new Text(theme.fg("dim", "↑↓ navigate · enter select · esc cancel")));
                container.addChild(new DynamicBorder((str: string) => theme.fg("accent", str)));
                return {
                    render: (w: number) => container.render(w),
                    invalidate: () => container.invalidate(),
                    handleInput: (data: string) => {
                        selectList.handleInput(data);
                        tui.requestRender();
                    },
                };
            });
            if (!choice) return;

            const [provider, ...idParts] = choice.split("/");
            const id = idParts.join("/");
            const model = ctx.modelRegistry.find(provider, id);
            if (!model) {
                ctx.ui.notify(`Model not found in registry: ${choice}`, "error");
                return;
            }

            const ok = await pi.setModel(model);
            if (!ok) {
                ctx.ui.notify(
                    `No API key for ${choice}. Set OPENCODE_API_KEY in your env.`,
                    "error",
                );
                return;
            }
            ctx.ui.notify(`Switched to ${model.name} · ${SUGGESTED_USE[model.id] ?? heuristicUse(modelToRow(model))}`, "info");
        },
    });
}

