/**
 * Kanban Board Server — Bun HTTP server + orchestrator bridge.
 *
 * Serves the mobile-first Kanban UI, manages board state via an API,
 * dispatches Pi orchestration per phase, and broadcasts live updates via SSE.
 *
 * Env vars:
 *   KANBAN_PORT           (default: 8799)
 *   KANBAN_HOST           (default: 0.0.0.0)
 *   KANBAN_ORCHESTRATOR_MODEL  (default: opencode-go/deepseek-v4-flash)
 *   KANBAN_CODE_MODEL          (default: opencode-go/deepseek-v4-flash)
 *   KANBAN_REVIEW_MODEL        (default: opencode-go/glm-5.2)
 *   KANBAN_PLAN_MODEL         (default: opencode-go/glm-5.2)
 *   KANBAN_PHASE_TIMEOUT      (default: 600000)
 *   KANBAN_MAX_REVIEW_CYCLES      (default: 5)
 *
 * Usage: bun run src/server.ts
 *        (or `just kanban` which sources .env first)
 */

import { readFileSync, existsSync, mkdirSync, writeFileSync, rmSync, statSync, readdirSync } from "node:fs";
import { resolve, dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { homedir, networkInterfaces } from "node:os";
import { spawn } from "node:child_process";
import { RpcClient } from "@earendil-works/pi-coding-agent";

import {
  loadState,
  addTicket,
  updateTicket,
  deleteTicket,
  getTicket,
  moveTicketToLane,
  setTicketRunning,
  setTicketDone,
  setTicketBlocked,
  setPrUrl,
  setTicketMerged,
  setCurrentPhase,
  clearCurrentPhase,
  clearMergedTickets,
  appendPhaseEntry,
  addProject,
  updateProject,
  deleteProject,
  getProject,
  getLaneModels,
  setLaneModels,
  getRepoScanRoot,
  setRepoScanRoot,
  onTicketStatusChange,
  modelForLane,
  formatModelRef,
  generateBranchName,
  LANES,
  createChildTicket,
  getChildTickets,
  allChildrenComplete,
  type Lane,
  type Ticket,
  type PhaseEntry,
  type CurrentPhase,
  type ProjectConfig,
  type LaneModels,
} from "./board.ts";

import { planPrompt, inProgressPrompt, reviewPrompt, orchestratorPlanPrompt, parsePhaseResult, type PhaseResult, type PromptVars } from "./prompts.ts";

// ═══════════════════════════════════════════════════════════════════════════
// Config
// ═══════════════════════════════════════════════════════════════════════════

const PORT = parseInt(process.env.KANBAN_PORT || "8799", 10);
const HOST = process.env.KANBAN_HOST || "0.0.0.0";
const MAX_REVIEW_CYCLES = parseInt(process.env.KANBAN_MAX_REVIEW_CYCLES || "5", 10);
const MAX_PLAN_RETRIES = 3;
const MIN_PLAN_LENGTH = 250; // minimum chars of plan notes before presenting for approval
const PHASE_TIMEOUT_MS = parseInt(process.env.KANBAN_PHASE_TIMEOUT || "600000", 10); // 10 min default
const MAX_PHASE_RETRIES = parseInt(process.env.KANBAN_MAX_PHASE_RETRIES || "3", 10);
const MAX_CHILD_TICKETS = parseInt(process.env.KANBAN_MAX_CHILD_TICKETS || "50", 10);

// Detect LAN IP for Plannotator URLs
function detectLanIp(): string {
  try {
    const ifaces = networkInterfaces();
    for (const name of Object.keys(ifaces).sort()) {
      for (const iface of ifaces[name] || []) {
        if (!iface.internal && iface.family === "IPv4" && iface.address) {
          return iface.address;
        }
      }
    }
  } catch {}
  return process.env.LAN_IP || "127.0.0.1";
}
const LAN_IP = detectLanIp();

// Resolve the pi CLI entry from the installed @earendil-works/pi-coding-agent package
const scriptDir = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(scriptDir, "..");
const pkgEntry = fileURLToPath(import.meta.resolve("@earendil-works/pi-coding-agent"));
const cliPath = resolve(dirname(pkgEntry), "cli.js");

// ═══════════════════════════════════════════════════════════════════════════
// SSE Client management
// ═══════════════════════════════════════════════════════════════════════════

interface SseClient {
  controller: ReadableStreamDefaultController;
  controllerClosed: boolean;
}

const sseClients = new Set<SseClient>();

function broadcast(event: string, data: unknown) {
  const message = `event: ${event}\ndata: ${JSON.stringify(data)}\n\n`;
  const encoded = new TextEncoder().encode(message);
  for (const client of sseClients) {
    if (client.controllerClosed) {
      sseClients.delete(client);
      continue;
    }
    try {
      client.controller.enqueue(encoded);
    } catch {
      client.controllerClosed = true;
      sseClients.delete(client);
    }
  }
}

function broadcastBoardUpdate() {
  const state = loadState();
  broadcast("board", {
    tickets: state.tickets,
    projects: state.projects,
    laneModels: state.laneModels,
    repoScanRoot: state.repoScanRoot,
  });
}

function broadcastTicketUpdate(ticket: Ticket) {
  broadcast("ticket", ticket);
}

// ═══════════════════════════════════════════════════════════════════════════
// Running processes (for abort)
// ═══════════════════════════════════════════════════════════════════════════

interface RunningPhase {
  abort: () => Promise<void>;
  startedAt: number;
}
const runningPhases = new Map<string, RunningPhase>();

// Tickets whose phase should be auto-restarted after current phase cleanup
// (triggered by model settings change while ticket is in-flight)
const restartPending = new Map<string, Lane>();

// Per-ticket log buffer (so the UI can replay logs when opening the modal)
const ticketLogs = new Map<string, string[]>();

// Available models cache (populated on first request)
let _availableModels: { provider: string; modelId: string; name?: string }[] | null = null;

async function getAvailableModels(): Promise<{ provider: string; modelId: string; name?: string }[]> {
  if (_availableModels) return _availableModels;
  try {
    const proc = spawn("pi", ["--list-models"], {
      stdio: ["ignore", "pipe", "pipe"],
      timeout: 15000,
    });
    let stdout = "";
    for await (const chunk of proc.stdout!) {
      stdout += chunk;
    }
    const lines = stdout.split("\n").slice(1).filter(Boolean);
    const models: { provider: string; modelId: string; name?: string }[] = [];
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith("-") || trimmed.startsWith("All")) continue;
      const parts = trimmed.split(/\s{2,}/);
      if (parts.length >= 2) {
        const provider = parts[0].trim();
        const modelId = parts[1].trim();
        if (provider && modelId) {
          models.push({ provider, modelId });
        }
      }
    }
    _availableModels = models;
    return models;
  } catch {
    // Fallback: known opencode-go models
    const fallback = [
      "deepseek-v4-flash",
      "deepseek-v4-pro",
      "glm-5.1",
      "glm-5.2",
      "kimi-k2.6",
      "kimi-k2.7-code",
      "mimo-v2.5",
      "mimo-v2.5-pro",
      "minimax-m2.7",
      "minimax-m3",
      "qwen3.6-plus",
      "qwen3.7-max",
      "qwen3.7-plus",
    ];
    _availableModels = fallback.map((m) => ({ provider: "opencode-go", modelId: m }));
    return _availableModels;
  }
}
const _subagentLengths = new Map<string, number>();

function log(ticketId: string, line: string) {
  if (!ticketLogs.has(ticketId)) ticketLogs.set(ticketId, []);
  const buf = ticketLogs.get(ticketId)!;
  buf.push(line);
  if (buf.length > 200) buf.splice(0, buf.length - 200); // keep last 200 lines
  broadcast("log", { ticketId, line });
}

// Wire up the status-change logging hook from board.ts so every
// ticket status transition (idle→running, running→blocked, etc.)
// appears as a live log line in the ticket modal.
onTicketStatusChange((ticketId, status) => {
  log(ticketId, `[status] Status → ${status}`);
});

// ═══════════════════════════════════════════════════════════════════════════
// Git operations  (per-ticket temp clones)
// ═══════════════════════════════════════════════════════════════════════════

function expandPath(p: string): string {
  if (p.startsWith("~/")) return resolve(homedir(), p.slice(2));
  return resolve(p);
}

/**
 * Generate a concise ticket title from a description using the orchestrator model.
 * Reuses the same LLM call as the /api/generate-title endpoint.
 */
async function generateTitle(description: string): Promise<string> {
  const desc = description?.trim() || "";
  if (!desc) return "";

  const titleModel = formatModelRef(modelForLane("orchestrator"));
  const prompt = [
    "Generate a concise Git ticket title (max 60 chars) for this description:",
    "",
    desc,
    "",
    "Output ONLY the title text. No quotes, no explanation, no punctuation at end.",
  ].join("\n");

  let rpc;
  try {
    let finalText = "";
    rpc = new RpcClient({
      cwd: REPO_ROOT,
      cliPath,
      env: {
        ...(process.env as Record<string, string>),
        PI_CODING_AGENT_DIR: resolve(homedir(), ".pi", "agent"),
      },
      model: titleModel,
      args: ["--no-session"],
    });

    rpc.onEvent((event: any) => {
      if (event.type === "message_end" && event.message?.role === "assistant") {
        const text = extractText(event.message);
        if (text) finalText = text;
      }
    });

    await rpc.start();
    await rpc.prompt(prompt);
    await rpc.waitForIdle(60000);

    const lastText = await rpc.getLastAssistantText();
    const result = lastText || finalText;
    return (result || "")
      .trim()
      .replace(/^["']|["']$/g, "")
      .slice(0, 60);
  } catch (err: any) {
    console.error("[kanban] generate-title error:", err);
    return "";
  } finally {
    if (rpc)
      try {
        await rpc.stop();
      } catch {}
  }
}

function projectPath(project: ProjectConfig): string {
  return expandPath(project.path);
}

const CLONES_DIR = resolve(REPO_ROOT, "state", "clones");
const RUNS_DIR = resolve(REPO_ROOT, "state", "runs");

function ensureCloneDirs() {
  if (!existsSync(CLONES_DIR)) mkdirSync(CLONES_DIR, { recursive: true, mode: 0o700 });
  if (!existsSync(RUNS_DIR)) mkdirSync(RUNS_DIR, { recursive: true, mode: 0o700 });
}

function ticketCloneDir(ticketId: string): string {
  return resolve(CLONES_DIR, ticketId);
}

function cleanupTicketClone(ticketId: string) {
  try {
    const dir = ticketCloneDir(ticketId);
    if (existsSync(dir)) rmSync(dir, { recursive: true, force: true });
  } catch {}
}

/**
 * Push the branch from a ticket's clone to origin.
 */
async function pushBranchFromClone(ticketId: string): Promise<boolean> {
  const dir = ticketCloneDir(ticketId);
  if (!existsSync(dir)) return false;
  log(ticketId, "[git] Pushing branch to origin...");
  const { exitCode } = await execGitCwd(dir, ["push", "-u", "origin", "HEAD"]);
  if (exitCode !== 0) {
    log(ticketId, `[git] Push failed (exit ${exitCode}) — retrying once`);
    const { exitCode: retryOk } = await execGitCwd(dir, ["push", "-u", "origin", "HEAD"]);
    return retryOk === 0;
  }
  return true;
}

/**
 * Ensure a ticket's clone exists and is on the right branch.
 * If the clone dir is missing, try to re-clone from remote.
 */
async function ensureClone(ticket: Ticket, project: ProjectConfig): Promise<boolean> {
  const dir = ticketCloneDir(ticket.id);
  if (existsSync(dir)) {
    const { stdout: branch } = await execGitCwd(dir, ["rev-parse", "--abbrev-ref", "HEAD"]);
    if (branch.trim() === ticket.branch) {
      // Already on the right branch — freshen up with latest default branch
      await mergeDefaultBranchIntoTicket(ticket, project);
      return true;
    }
    log(ticket.id, `[git] Local clone on wrong branch, checking remote for ${ticket.branch}...`);
    const { exitCode: fetchOk } = await execGitCwd(dir, ["fetch", "origin", ticket.branch]);
    if (fetchOk === 0) {
      const { exitCode: co } = await execGitCwd(dir, ["checkout", "-b", ticket.branch, `origin/${ticket.branch}`]);
      if (co !== 0) return false;
      await mergeDefaultBranchIntoTicket(ticket, project);
      return true;
    }
    cleanupTicketClone(ticket.id);
  }
  log(ticket.id, `[git] Ensuring clone for ${ticket.branch}...`);
  const remoteUrl = await resolveAndCacheRemoteUrl(project);
  if (!remoteUrl) return false;
  ensureCloneDirs();
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true, mode: 0o700 });
  const { exitCode: cloneBranchOk } = await execGitCwd(dir, ["clone", "--depth=1", "--branch", ticket.branch, "--single-branch", remoteUrl, "."]);
  if (cloneBranchOk === 0) {
    await mergeDefaultBranchIntoTicket(ticket, project);
    return true;
  }
  log(ticket.id, `[git] Branch ${ticket.branch} not on remote yet, cloning default branch...`);
  cleanupTicketClone(ticket.id);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true, mode: 0o700 });
  const { exitCode: cloneDefaultOk } = await execGitCwd(dir, ["clone", "--depth=1", remoteUrl, "."]);
  if (cloneDefaultOk !== 0) return false;

  // Shallow clone only fetches the remote's default branch (e.g. main).
  // If the project's defaultBranch is different (e.g. develop), fetch it now
  // using an explicit refspec so a remote tracking ref is created.
  if (project.defaultBranch !== "main") {
    log(ticket.id, `[git] ensureClone: fetching ${project.defaultBranch}...`);
    const { exitCode: fetchBr } = await execGitCwd(dir, ["fetch", "origin", `+refs/heads/${project.defaultBranch}:refs/remotes/origin/${project.defaultBranch}`, "--depth=1"]);
    if (fetchBr !== 0) {
      log(ticket.id, `[git] ensureClone: could not fetch ${project.defaultBranch} — falling back to origin/HEAD`);
      const { exitCode: br } = await execGitCwd(dir, ["checkout", "-b", ticket.branch, "origin/HEAD"]);
      if (br !== 0) return false;
      await mergeDefaultBranchIntoTicket(ticket, project);
      return true;
    }
  }

  const { exitCode: br } = await execGitCwd(dir, ["checkout", "-b", ticket.branch, `origin/${project.defaultBranch}`]);
  if (br !== 0) return false;
  await mergeDefaultBranchIntoTicket(ticket, project);
  return true;
}

/**
 * Check whether a remote branch has at least one commit ahead of the default branch.
 * Unlike `ls-remote` (which returns a hash even for empty/up-to-date refs),
 * this distinguishes "branch with real content" from "empty ref with no diff".
 */
async function branchHasContent(project: ProjectConfig, branch: string): Promise<boolean> {
  const { stdout: ref } = await execGit(project, ["ls-remote", "--heads", "origin", branch]).catch(() => ({ stdout: "" }));
  if (!ref.trim()) return false;
  const { stdout: count } = await execGit(project, ["rev-list", "--count", `origin/${project.defaultBranch}..origin/${branch}`]).catch(() => ({ stdout: "0" }));
  return parseInt(count.trim(), 10) > 0;
}

/** Write a heartbeat file, used to detect dead phases after restart. */
function writeHeartbeat(ticketId: string) {
  const dir = ticketCloneDir(ticketId);
  if (!existsSync(dir)) return;
  try {
    writeFileSync(resolve(dir, ".heartbeat"), String(Date.now()), "utf-8");
  } catch {}
}

/** Check if a ticket's heartbeat is stale (older than maxAgeMs). */
function isHeartbeatStale(ticketId: string, maxAgeMs = 180_000): boolean {
  const dir = ticketCloneDir(ticketId);
  if (!existsSync(dir)) return true;
  const hbPath = resolve(dir, ".heartbeat");
  if (!existsSync(hbPath)) return true;
  try {
    return Date.now() - statSync(hbPath).mtimeMs > maxAgeMs;
  } catch {
    return true;
  }
}

/** Write a per-run audit file for post-mortem. */
function writePhaseRunFile(ticketId: string, phaseRunId: string, data: Record<string, unknown>) {
  try {
    const runDir = resolve(RUNS_DIR, ticketId);
    if (!existsSync(runDir)) mkdirSync(runDir, { recursive: true, mode: 0o700 });
    writeFileSync(resolve(runDir, `${phaseRunId}.json`), JSON.stringify(data, null, 2), "utf-8");
  } catch {}
}

/**
 * On startup, find orphaned running tickets and recover them.
 * Infers the phase from history + lane, recovers the clone from remote,
 * and re-runs the phase so no work is lost.
 */
async function reconcileOnStartup() {
  log("system", "[startup] Reconciling orphaned running tickets...");
  const state = loadState();
  let reconciled = 0;

  for (let ticket of state.tickets) {
    if (ticket.status !== "running" && !ticket.currentPhase) continue;
    const project = getProject(ticket.projectId);
    if (!project) {
      log(ticket.id, `[startup] No project — resetting to idle`);
      updateTicket(ticket.id, { status: "idle" });
      continue;
    }

    const cloneExists = existsSync(ticketCloneDir(ticket.id));
    const stale = isHeartbeatStale(ticket.id);

    // Infer phase for tickets without currentPhase (schema upgrade)
    if (!ticket.currentPhase) {
      const lastEntry = ticket.history[ticket.history.length - 1];
      let inferredLane: Lane | null = null;
      if (lastEntry && !lastEntry.endedAt) {
        inferredLane = lastEntry.phase;
      } else if (lastEntry && lastEntry.endedAt && ticket.lane !== lastEntry.phase) {
        inferredLane = ticket.lane;
      } else if (ticket.lane !== "backlog" && ticket.lane !== "done") {
        inferredLane = ticket.lane;
      }
      if (!inferredLane || inferredLane === "backlog" || inferredLane === "done") {
        log(ticket.id, `[startup] No actionable phase — resetting to idle`);
        updateTicket(ticket.id, { status: "idle" });
        reconciled++;
        continue;
      }
      setCurrentPhase(ticket.id, { lane: inferredLane, phaseRunId: null, startedAt: null });
      const reloaded = getTicket(ticket.id);
      if (!reloaded) continue;
      ticket = reloaded as typeof ticket & (typeof state.tickets)[0];
    }

    // Mark any incomplete history entry as interrupted
    const fresh = getTicket(ticket.id);
    if (fresh) {
      const lastEntry = fresh.history[fresh.history.length - 1];
      if (lastEntry && !lastEntry.endedAt) {
        lastEntry.endedAt = Date.now();
        lastEntry.notes = (lastEntry.notes || "") + "\n[interrupted by server restart]";
        lastEntry.success = false;
      }
      ticket = fresh as typeof ticket & (typeof state.tickets)[0];
    }

    const onRemote = await branchHasContent(project, ticket.branch);

    if (cloneExists && !stale && runningPhases.has(ticket.id)) {
      log(ticket.id, `[startup] Active phase with fresh heartbeat — leaving alone`);
      continue;
    }

    if (cloneExists || onRemote) {
      log(ticket.id, `[startup] Recovering clone and re-running ${ticket.currentPhase!.lane} phase...`);
      const ok = await ensureClone(ticket, project);
      if (!ok) {
        log(ticket.id, `[startup] Clone recovery failed — blocking`);
        appendPhaseEntry(ticket.id, {
          phase: ticket.currentPhase!.lane,
          model: "",
          startedAt: Date.now(),
          endedAt: Date.now(),
          notes: "Clone recovery failed on startup",
          findings: ["Clone recovery failed"],
          success: false,
        });
        setCurrentPhase(ticket.id, null);
        setTicketBlocked(ticket.id);
        reconciled++;
        continue;
      }
      log(ticket.id, `[startup] Re-running ${ticket.currentPhase!.lane} phase`);
      setCurrentPhase(ticket.id, { lane: ticket.currentPhase!.lane, phaseRunId: null, startedAt: null });
      runPhase(ticket.id, ticket.currentPhase!.lane);
      reconciled++;
    } else {
      log(ticket.id, `[startup] No work on remote — blocking`);
      appendPhaseEntry(ticket.id, {
        phase: ticket.currentPhase!.lane,
        model: "",
        startedAt: Date.now(),
        endedAt: Date.now(),
        notes: "Server restarted and no committed work was found",
        findings: ["Work lost — never pushed"],
        success: false,
      });
      setCurrentPhase(ticket.id, null);
      setTicketBlocked(ticket.id);
      reconciled++;
    }
  }
  log("system", `[startup] Reconciliation complete — ${reconciled} tickets processed`);
  broadcastBoardUpdate();
}

/** Run git with a specific cwd. */
async function execGitCwd(cwd: string, args: string[]): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  return new Promise((resolvePromise) => {
    const proc = spawn("git", args, { cwd, stdio: ["ignore", "pipe", "pipe"] });
    let stdout = "";
    let stderr = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });
    proc.stderr.on("data", (chunk: Buffer) => {
      stderr += chunk.toString();
    });
    proc.on("close", (exitCode) => {
      resolvePromise({ stdout, stderr, exitCode: exitCode ?? -1 });
    });
    proc.on("error", (err) => {
      resolvePromise({ stdout, stderr: err.message, exitCode: -1 });
    });
  });
}

/** Run a git command in the project's original repo (uses project path). */
async function execGit(project: ProjectConfig, args: string[]): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  return execGitCwd(projectPath(project), args);
}

/** Run a git command inside a ticket's temp clone. */
async function execGitTicket(ticketId: string, args: string[]): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  return execGitCwd(ticketCloneDir(ticketId), args);
}

/**
 * Resolve the effective remote URL for a project: try the local git remote first,
 * then fall back to the cached remoteUrl on the project config. Backfills the
 * cache when the local read succeeds but the cache is empty.
 */
async function resolveAndCacheRemoteUrl(project: ProjectConfig): Promise<string | null> {
  // Try the local path first (works when server runs on the same machine as the repo)
  const { stdout: localUrl } = await execGit(project, ["remote", "get-url", "origin"]).catch(() => ({ stdout: "" }));
  const trimmed = localUrl.trim();
  if (trimmed) {
    // Backfill the cached remoteUrl if missing (e.g. pre-existing project from before this field existed)
    if (!project.remoteUrl) {
      updateProject(project.id, { remoteUrl: trimmed });
    }
    return trimmed;
  }

  // Local path didn't yield a URL — use the cached remoteUrl (for servers running on a different machine)
  if (project.remoteUrl) {
    return project.remoteUrl;
  }

  return null;
}

/**
 * Fetch the latest default branch and merge it into the ticket's feature branch.
 * Ensures the feature branch is up to date before any work begins, so the AI
 * agent works against the freshest code and the eventual PR merge is cleaner.
 * Best-effort: logs failures but does not fail the clone.
 */
async function mergeDefaultBranchIntoTicket(ticket: Ticket, project: ProjectConfig): Promise<void> {
  log(ticket.id, `[git] Merging latest ${project.defaultBranch} into ${ticket.branch}...`);

  // Fetch latest default branch (deepen shallow history enough for a clean merge)
  const { exitCode: fetchOk } = await execGitTicket(ticket.id, ["fetch", "origin", project.defaultBranch, "--depth=50"]).catch(() => ({ exitCode: -1, stdout: "", stderr: "" }));
  if (fetchOk !== 0) {
    log(ticket.id, `[git] Could not fetch latest ${project.defaultBranch} — continuing with existing clone`);
    return;
  }

  // Merge into current branch (should be a clean fast-forward on a fresh clone)
  const { exitCode: mergeOk, stderr: mergeErr } = await execGitTicket(ticket.id, ["merge", `origin/${project.defaultBranch}`, "--no-edit"]).catch(() => ({ exitCode: -1, stdout: "", stderr: "" }));
  if (mergeOk !== 0) {
    // Merge conflict — abort and log, the AI agent will still have the original base
    await execGitTicket(ticket.id, ["merge", "--abort"]).catch(() => {});
    log(ticket.id, `[git] Merge conflict when merging ${project.defaultBranch} — continuing with original base: ${mergeErr.slice(0, 200)}`);
    return;
  }

  log(ticket.id, `[git] ${ticket.branch} is up to date with latest ${project.defaultBranch}`);
}

/**
 * Clone the project repo into an isolated temp directory and create the
 * feature branch off the default branch.
 */
async function cloneForTicket(ticket: Ticket, project: ProjectConfig): Promise<boolean> {
  const dir = ticketCloneDir(ticket.id);
  ensureCloneDirs();
  cleanupTicketClone(ticket.id);
  mkdirSync(dir, { recursive: true, mode: 0o700 });

  const remoteUrl = await resolveAndCacheRemoteUrl(project);
  if (!remoteUrl) {
    log(ticket.id, `[git] No remote URL available for project "${project.name}" — set a remote URL in project settings`);
    return false;
  }

  log(ticket.id, `[git] Cloning ${remoteUrl} to ${dir}...`);
  const { exitCode: cloneOk } = await execGitCwd(dir, ["clone", "--depth=1", remoteUrl, "."]);
  if (cloneOk !== 0) return false;

  // Shallow clone only fetches the remote's default branch (e.g. main).
  // If the project's defaultBranch is different (e.g. develop), fetch it now
  // using an explicit refspec so a remote tracking ref is created.
  if (project.defaultBranch !== "main") {
    log(ticket.id, `[git] Fetching project default branch ${project.defaultBranch}...`);
    const { exitCode: fetchBr } = await execGitCwd(dir, ["fetch", "origin", `+refs/heads/${project.defaultBranch}:refs/remotes/origin/${project.defaultBranch}`, "--depth=1"]);
    if (fetchBr !== 0) {
      log(ticket.id, `[git] Could not fetch ${project.defaultBranch} — falling back to origin/HEAD`);
      // Try the remote HEAD instead
      const { exitCode: br } = await execGitCwd(dir, ["checkout", "-b", ticket.branch, "origin/HEAD"]);
      if (br !== 0) return false;
      await mergeDefaultBranchIntoTicket(ticket, project);
      return true;
    }
  }

  log(ticket.id, `[git] Creating branch ${ticket.branch} from origin/${project.defaultBranch}...`);
  const { exitCode: br } = await execGitCwd(dir, ["checkout", "-b", ticket.branch, `origin/${project.defaultBranch}`]);
  if (br !== 0) return false;

  // Merge latest default branch so the AI agent works against the freshest code
  await mergeDefaultBranchIntoTicket(ticket, project);
  return true;
}

async function createPR(project: ProjectConfig, branch: string, title: string, body: string, cwd?: string): Promise<string | null> {
  const workDir = cwd ?? projectPath(project);

  // Step 1: try gh pr create
  const primaryResult = await new Promise<string | null>((resolvePromise) => {
    const proc = spawn("gh", ["pr", "create", "--base", project.defaultBranch, "--head", branch, "--title", title, "--body", body], {
      cwd: workDir,
      stdio: ["ignore", "pipe", "pipe"],
    });
    let stdout = "",
      stderr = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });
    proc.stderr.on("data", (chunk: Buffer) => {
      stderr += chunk.toString();
    });
    proc.on("close", (exitCode) => {
      if (exitCode === 0) {
        resolvePromise(stdout.trim() || null);
      } else {
        const urlMatch = stderr.match(/https:\/\/github\.com\/\S+\/pull\/\d+/);
        if (urlMatch) resolvePromise(urlMatch[0]);
        else resolvePromise("__retry__");
      }
    });
    proc.on("error", () => resolvePromise(null));
  });
  if (primaryResult !== "__retry__") return primaryResult;

  // Step 2: gh pr create failed — try gh pr list to find existing PR
  return new Promise<string | null>((resolvePromise) => {
    const proc = spawn("gh", ["pr", "list", "--head", branch, "--json", "url", "--limit", "1"], { cwd: workDir, stdio: ["ignore", "pipe", "pipe"] });
    let stdout = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });
    proc.on("close", (exitCode) => {
      if (exitCode === 0) {
        try {
          const parsed = JSON.parse(stdout.trim());
          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0].url) {
            resolvePromise(parsed[0].url);
            return;
          }
        } catch {}
      }
      resolvePromise(null);
    });
    proc.on("error", () => resolvePromise(null));
  });
}

/**
 * Check if gh CLI is available.
 */
async function checkGh(): Promise<boolean> {
  return new Promise((resolvePromise) => {
    const proc = spawn("gh", ["--version"], { stdio: ["ignore", "pipe", "pipe"] });
    proc.on("close", (code) => resolvePromise(code === 0));
    proc.on("error", () => resolvePromise(false));
  });
}

/**
 * Check if a PR has been merged on GitHub.
 * Uses gh pr view --json mergedAt and returns true if a mergedAt timestamp exists.
 */
async function checkPrMerged(prUrl: string): Promise<boolean> {
  const match = prUrl.match(/\/pull\/(\d+)/);
  if (!match) return false;
  const prNumber = match[1];

  return new Promise((resolve) => {
    const proc = spawn("gh", ["pr", "view", prNumber, "--json", "mergedAt", "-q", ".mergedAt"], {
      stdio: ["ignore", "pipe", "pipe"],
    });
    let stdout = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });
    proc.on("close", (exitCode) => {
      if (exitCode === 0 && stdout.trim()) {
        resolve(true);
      } else {
        resolve(false);
      }
    });
    proc.on("error", () => resolve(false));
  });
}

/**
 * Poll all done tickets with unmerged PRs to check if they've been merged.
 */
async function pollPrMergeStatus() {
  const state = loadState();
  for (const ticket of state.tickets) {
    if (ticket.prUrl && ticket.lane === "done" && !ticket.merged) {
      const merged = await checkPrMerged(ticket.prUrl);
      if (merged) {
        setTicketMerged(ticket.id);
        console.log(`[kanban] PR merged for ticket ${ticket.id}: ${ticket.prUrl}`);
        broadcastBoardUpdate();
      }
    }
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// Orchestrator dispatch
// ═══════════════════════════════════════════════════════════════════════════

function buildPrompt(ticket: Ticket, project: ProjectConfig, lane: Lane): string {
  const modelRef = modelForLane(lane);
  const modelStr = formatModelRef(modelRef);
  // Use the ticket's temp clone path for prompt context (caller ensures clone exists)
  const workDir = ticketCloneDir(ticket.id);
  const vars: PromptVars = {
    title: ticket.title,
    description: ticket.description,
    branch: ticket.branch,
    path: workDir,
    defaultBranch: project.defaultBranch,
    model: modelStr,
    maxReviewCycles: MAX_REVIEW_CYCLES,
    currentReviewCycle: lane === "review" ? ticket.reviewCycle + 1 : undefined,
    context: buildPhaseContext(ticket, lane),
  };

  switch (lane) {
    case "plan":
      if (ticket.orchestratorMode) {
        return orchestratorPlanPrompt(vars);
      }
      return planPrompt(vars);
    case "in_progress":
      return inProgressPrompt(vars);
    case "review":
      return reviewPrompt(vars);
    default:
      return "";
  }
}

/**
 * Build a context string from the ticket's recent history for the current phase.
 */
function buildPhaseContext(ticket: Ticket, lane: Lane): string {
  // Collect recent history entries from the previous phase
  const relevant = ticket.history.filter((h) => h.phase !== lane).slice(-3);
  let historyStr = "";
  if (relevant.length > 0) {
    historyStr = relevant
      .map((h) => {
        const model = h.model;
        const status = h.success === null ? "incomplete" : h.success ? "passed" : "failed";
        return `[${h.phase}] (${model}, ${status}): ${h.notes}${h.findings.length ? "\n  Findings:\n  - " + h.findings.join("\n  - ") : ""}`;
      })
      .join("\n\n");
  }
  // Include user feedback from a previous plan run — append to history
  if (lane === "plan" && ticket.planFeedback) {
    const feedback = `User feedback on previous plan: "${ticket.planFeedback}"`;
    if (historyStr) return `${historyStr}\n\n${feedback}`;
    return feedback;
  }
  return historyStr;
}

/**
 * Decide the next lane after a phase completes.
 * Returns the next lane or "done" to stop, or "blocked" for max cycles.
 */
function decideNextLane(ticket: Ticket, result: PhaseResult): { lane: Lane | "done" | "blocked"; reason: string } {
  const currentLane = ticket.lane;

  if (currentLane === "plan") {
    if (ticket.autoApprove) {
      // Auto-approve: skip human interaction, go straight to implementation
      return { lane: "in_progress", reason: "Auto-approve enabled — moving to implementation" };
    }
    if (ticket.orchestratorMode) {
      // Orchestrator mode: stay in plan — wait for user questions to be answered
      return { lane: "plan", reason: "Orchestrator questions completed — waiting for answers" };
    }
    // After planning, stay in plan — wait for user approval or feedback
    return { lane: "plan", reason: "Plan completed — waiting for approval" };
  }

  if (currentLane === "in_progress") {
    // After implementation — skip review if unchecked
    if (ticket.skipReview) {
      return { lane: "done", reason: "Implementation complete — review skipped per ticket settings, moving to done" };
    }
    return { lane: "review", reason: "Implementation complete, moving to review" };
  }

  if (currentLane === "review") {
    if (result.success) {
      return { lane: "done", reason: "Review clean, moving to done" };
    } else {
      // Review found issues — move to plan so user can review and decide what to do
      if (ticket.reviewCycle >= MAX_REVIEW_CYCLES) {
        return { lane: "blocked", reason: `Exceeded max review cycles (${MAX_REVIEW_CYCLES})` };
      }
      return { lane: "plan", reason: `Review found ${result.findings.length} issues — moved to plan for user feedback` };
    }
  }

  return { lane: "done", reason: "Phase complete" };
}

function extractText(msg: any): string {
  if (!msg?.content) return "";
  const parts = Array.isArray(msg.content) ? msg.content : [];
  return parts
    .filter((c: any) => c.type === "text")
    .map((c: any) => c.text ?? "")
    .join("");
}

// ─── Orchestrator helpers ────────────────────────────────────────────

interface ChildTicketBreakdown {
  title: string;
  description: string;
  order: number;
}

/**
 * Parse child ticket breakdown from the orchestrator plan notes.
 * Looks for patterns like "## Ticket N: <Title>" followed by Description.
 */
function parseOrchestratorBreakdown(ticket: Ticket): ChildTicketBreakdown[] {
  // Get the last plan phase notes
  const lastPlan = [...ticket.history].reverse().find((h) => h.phase === "plan");
  if (!lastPlan) return [];

  const notes = lastPlan.notes;
  const children: ChildTicketBreakdown[] = [];

  // Pattern: ## Ticket N: Title or ## Ticket N — Title
  // followed by Description: ...
  const ticketRegex = /##\s*Ticket\s*(\d+)\s*[:\u2014-]\s*([^\n]+)\n([\s\S]*?)(?=\n##|$)/g;
  let match;
  while ((match = ticketRegex.exec(notes)) !== null) {
    const order = parseInt(match[1], 10);
    const title = match[2].trim();
    const body = match[3].trim();

    // Try to extract description from body
    let description = body;
    const descMatch = body.match(/Description\s*[:\u2014-]\s*([^\n]+)/);
    if (descMatch) {
      description = descMatch[1].trim();
      // Also include surrounding context for better descriptions
      const contextLines = body.split("\n").filter((l) => {
        const t = l.trim();
        return t && !t.match(/^Description\s*[:\u2014-]/i) && t !== match[2].trim();
      });
      if (contextLines.length > 0) {
        description += "\n\n" + contextLines.slice(0, 5).join("\n");
      }
    }

    children.push({ title: title || `Child Ticket ${order}`, description: description.slice(0, 2000), order });
  }

  // Fallback: simpler pattern for bullet-list style breakdowns
  if (children.length === 0) {
    const simpleRegex = /\*\*Ticket\s*(\d+)\s*[:\u2014-]\s*([^\n]+)\*\*\n([\s\S]*?)(?=\n\*\*Ticket|$)/g;
    while ((match = simpleRegex.exec(notes)) !== null) {
      const order = parseInt(match[1], 10);
      const title = match[2].trim();
      const body = match[3].trim();
      children.push({ title, description: body.slice(0, 2000), order });
    }
  }

  return children.sort((a, b) => a.order - b.order);
}

/**
 * Orchestrate child tickets: start them sequentially and advance the parent when done.
 * Uses the status change callback to detect child completion.
 */
async function orchestrateChildren(parentId: string, project: ProjectConfig) {
  const parent = getTicket(parentId);
  if (!parent || !parent.childIds || parent.childIds.length === 0) {
    log(parentId, "[orchestrator] No children to orchestrate");
    return;
  }

  const childIds = [...parent.childIds];
  let currentChildIndex = 0;
  let orchestratorActive = true;
  // Guard flag to prevent re-entrant onChildChange when we call setTicketBlocked
  // (which synchronously fires status callbacks, which would race with our own index increment)
  let advancingChild = false;

  // Register parent in runningPhases so abort/move/restart handlers don't race
  const orchestratorPhase: RunningPhase = {
    abort: async () => {
      log(parentId, "[orchestrator] Aborting orchestration...");
      orchestratorActive = false;
      unregisterOrchestratorCb();
      cleanupTicketClone(parentId);
      moveTicketToLane(parentId, "backlog");
      updateTicket(parentId, { childIds: undefined });
      broadcastBoardUpdate();
    },
    startedAt: Date.now(),
  };
  runningPhases.set(parentId, orchestratorPhase);

  // Set parent currentPhase for crash-recovery visibility
  setCurrentPhase(parentId, { lane: "in_progress", phaseRunId: "orchestrator", startedAt: Date.now() });

  /**
   * Start the next child ticket in the sequence.
   */
  async function startNextChild() {
    if (!orchestratorActive) return;

    while (currentChildIndex < childIds.length) {
      const childId = childIds[currentChildIndex];
      const child = getTicket(childId);

      if (!child) {
        log(parentId, `[orchestrator] Child ticket ${childId} not found — skipping`);
        currentChildIndex++;
        continue;
      }

      // Skip already-done children
      if (child.lane === "done" || child.cancelled) {
        log(parentId, `[orchestrator] Child "${child.title}" already done — skipping`);
        currentChildIndex++;
        continue;
      }

      log(parentId, `[orchestrator] Starting child ${currentChildIndex + 1}/${childIds.length}: "${child.title}"...`);
      broadcastBoardUpdate();

      // Clone the repo for this child
      const cloneOk = await cloneForTicket(child, project);
      if (!cloneOk) {
        log(parentId, `[orchestrator] Failed to clone for child ${child.id} — blocking`);
        advancingChild = true;
        try {
          setTicketBlocked(child.id);
        } finally {
          advancingChild = false;
        }
        broadcastBoardUpdate();
        currentChildIndex++;
        continue; // move to next child in the while loop
      }

      // Move to plan — will auto-approve and proceed through the pipeline
      moveTicketToLane(child.id, "plan");
      broadcastBoardUpdate();
      log(child.id, `[orchestrator] Starting plan phase (auto-approve enabled)...`);
      runPhase(child.id, "plan");
      // Wait for this child to complete (onChildChange callback advances index)
      return;
    }

    // All children processed — finalize
    await finalizeParent();
  }

  /**
   * Check if all children are done and advance the parent.
   */
  async function finalizeParent() {
    if (!orchestratorActive) return;
    orchestratorActive = false;

    // Clean up the running phase registration and callback
    runningPhases.delete(parentId);
    unregisterOrchestratorCb();
    clearCurrentPhase(parentId);

    const allDone = allChildrenComplete(parentId);
    if (allDone) {
      log(parentId, "[orchestrator] All children complete!");

      const parentTicket = getTicket(parentId);
      if (!parentTicket) return;

      // Build a summary of child PRs
      const childPrLinks = childIds
        .map((cid) => {
          const c = getTicket(cid);
          if (!c) return "";
          const prLink = c.prUrl ? `PR: ${c.prUrl}` : "(no PR — may have auto-merged)";
          const status = c.cancelled ? "[cancelled]" : c.lane === "done" ? "[done]" : `[${c.lane}]`;
          return `- ${c.title} ${status} — ${prLink}`;
        })
        .filter(Boolean)
        .join("\n");

      log(parentId, `[orchestrator] All children complete — moving parent to done`);
      log(parentId, `[orchestrator] Child PRs:\n${childPrLinks}`);

      // Record summary in parent's history and move to done
      appendPhaseEntry(parentId, {
        phase: "done",
        model: "orchestrator",
        startedAt: Date.now(),
        endedAt: Date.now(),
        notes: `All ${childIds.length} child tickets completed.\n\nChild PRs:\n${childPrLinks}`,
        findings: [],
        success: true,
      });

      setTicketDone(parentId);
      cleanupTicketClone(parentId);
      broadcastBoardUpdate();
      log(parentId, "[orchestrator] Parent ticket completed!");
    } else {
      log(parentId, "[orchestrator] Some children still incomplete — parent stays in progress");
    }
  }

  // Register status change handler to detect child completion
  let unregisterOrchestratorCb = () => {};
  const onChildChange = (changedId: string, status: string) => {
    if (!orchestratorActive) return;
    if (advancingChild) return; // guard: don't process callbacks we triggered synchronously
    const changedTicket = getTicket(changedId);
    if (!changedTicket || changedTicket.parentId !== parentId) return;

    // Child ticket completed a phase or reached done/blocked
    if (status === "done" || changedTicket.lane === "done" || status === "blocked") {
      log(parentId, `[orchestrator] Child "${changedTicket.title}" completed (status=${status}, lane=${changedTicket.lane})`);
      currentChildIndex++;
      // Small delay to let state settle, then start next
      setTimeout(() => startNextChild(), 1000);
    }
  };

  const maybeUnsub = onTicketStatusChange(onChildChange);
  if (typeof maybeUnsub === "function") {
    unregisterOrchestratorCb = maybeUnsub;
  }
  orchestratorActive = true;

  // Register heartbeat while orchestrating
  // Heartbeat runs for the entire orchestration; cleaned up in finalizeParent
  let beat = 0;
  const heartbeatTimer = setInterval(() => {
    beat++;
    log(parentId, `[orchestrator] ⏳ Orchestrating children... (${beat * 15}s elapsed)`);
    writeHeartbeat(parentId);
  }, 15000);
  writeHeartbeat(parentId);

  // Wrap finalizeParent to clean up heartbeat
  const originalFinalize = finalizeParent;
  finalizeParent = async () => {
    clearInterval(heartbeatTimer);
    await originalFinalize();
  };

  orchestratorActive = true;

  // Start the first child
  try {
    await startNextChild();
  } catch (err: any) {
    log(parentId, `[orchestrator] Error: ${err.message}`);
    clearInterval(heartbeatTimer);
    orchestratorActive = false;
    runningPhases.delete(parentId);
    unregisterOrchestratorCb();
    clearCurrentPhase(parentId);
  }
}

async function runPhase(ticketId: string, lane: Lane) {
  let ticket = getTicket(ticketId);
  if (!ticket) return;

  const project = getProject(ticket.projectId);
  if (!project) {
    console.error(`[kanban] Ticket ${ticketId}: project not found`);
    return;
  }

  if (lane === "done") {
    await handlePR(ticket, project);
    return;
  }

  // Plannotator path — skip subagent, create plan file, show URL
  if (lane === "plan" && ticket.usePlannotator) {
    const plansDir = resolve(REPO_ROOT, "plans");
    if (!existsSync(plansDir)) mkdirSync(plansDir, { recursive: true, mode: 0o755 });
    const planPath = resolve(plansDir, `${ticket.id}.md`);
    const planContent = [
      `# Plan: ${ticket.title}`,
      "",
      "## Ticket",
      `- **Title**: ${ticket.title}`,
      `- **Description**: ${ticket.description || "(none)"}`,
      `- **Branch**: \`${ticket.branch}\``,
      `- **Project**: ${project.name}`,
      `- **Project path**: \`${project.path}\``,
      "",
      "---",
      "",
      "Run `pi --plan` in the project directory to create and iterate on the plan.",
      "When the plan is ready, click **Approve Plan** in the kanban board.",
    ].join("\n");
    writeFileSync(planPath, planContent, "utf-8");

    const planUrl = `http://${LAN_IP}:19432`;
    updateTicket(ticketId, {
      planUrl,
      status: "idle",
      lane: "plan",
    });
    clearCurrentPhase(ticketId);
    broadcastBoardUpdate();
    log(ticketId, `[plannotator] Plan file created at ${planPath}`);
    log(ticketId, `[plannotator] URL: ${planUrl}`);
    return;
  }

  // Persist phase intent to disk
  const phaseRunId = crypto.randomUUID();
  setCurrentPhase(ticketId, { lane, phaseRunId, startedAt: Date.now() });
  ticket = setTicketRunning(ticketId);
  if (!ticket) return;
  broadcastTicketUpdate(ticket);

  const modelRef = modelForLane(lane);
  const modelStr = formatModelRef(modelRef);
  const orchestratorModel = formatModelRef(modelForLane("orchestrator"));
  const skillPath =
    lane === "review"
      ? resolve(REPO_ROOT, ".pi/skills/reviewer")
      : lane === "plan"
        ? resolve(REPO_ROOT, ".pi/skills/planner")
        : resolve(REPO_ROOT, ".pi/skills/coder");

  const prompt = buildPrompt(ticket, project, lane);
  const phaseStartedAt = Date.now();

  console.log(`[kanban] Running ${lane} for ticket ${ticketId} (orchestrator: ${orchestratorModel}, subagent: ${modelStr})`);
  log(ticketId, `[${new Date().toISOString()}] 🤖 Starting ${lane} phase`);
  log(ticketId, `    Orchestrator: ${orchestratorModel}`);
  log(ticketId, `    Phase model: ${modelStr}`);

  // Ensure the ticket's clone exists (recover from remote if needed)
  if (!existsSync(ticketCloneDir(ticketId))) {
    log(ticketId, `[git] Clone missing — attempting recovery for ${ticket.branch}...`);
    const recovered = await ensureClone(ticket, project);
    if (!recovered) {
      log(ticketId, `[git] Clone recovery failed — cannot proceed with ${lane} phase`);
      return;
    }
  }
  const workDir = ticketCloneDir(ticketId);

  // Spawn the orchestrator via RpcClient — retried on transient failures
  const buildRpc = () =>
    new RpcClient({
      cwd: workDir,
      cliPath,
      env: {
        ...(process.env as Record<string, string>),
        PI_CODING_AGENT_DIR: resolve(homedir(), ".pi", "agent"),
      },
      model: orchestratorModel,
      args: ["--skill", skillPath, "--no-session"],
    });

  let rpc = buildRpc();
  let finalAssistantText = "";
  let subagentOutput = "";
  let subagentError = false;

  // Named so it can be re-registered on retry
  const handleRpcEvent = (event: any) => {
    switch (event.type) {
      case "agent_start":
        log(ticketId, `▶  Agent started`);
        break;
      case "turn_start":
        log(ticketId, `↻  Turn start`);
        break;
      case "tool_execution_start":
        log(ticketId, `⚙️  Calling tool: ${event.toolName}`);
        if (event.toolName === "subagent" && event.args) {
          const m = event.args.model || event.args.agent || "";
          const task = event.args.task || "";
          if (m) log(ticketId, `    subagent model: ${m}`);
          if (task) log(ticketId, `    task: ${task.slice(0, 300)}`);
        }
        break;
      case "tool_execution_update":
        if (event.toolName === "subagent" && event.partialResult?.content) {
          const txt = event.partialResult.content
            .filter((c: any) => c.type === "text")
