            // ponytail: only keeps the last subagent's output if multiple subagent
            // calls happen in the same phase. Use a Map<toolCallId, string> if
            // multi-subagent phases become common.
            subagentOutput = txt;
            // Only broadcast the NEW text since last update for this tool call
            const key = `${ticketId}:${event.toolCallId}`;
            const lastLen = _subagentLengths.get(key) ?? 0;
            if (txt.length > lastLen) {
