              _subagentLengths.set(key, txt.length);
            }
          }
        }
        break;
      case "tool_execution_end":
        log(ticketId, `✅ Tool done: ${event.toolName}${event.isError ? " (error)" : ""}`);
        if (event.toolName === "subagent" && event.isError) subagentError = true;
        break;
      case "message_end":
        if (event.message?.role === "assistant") {
          const text = extractText(event.message);
          if (text) {
            finalAssistantText = text;
            const preview = text.length > 500 ? text.slice(0, 500) + "…" : text;
            log(ticketId, `💬 ${preview}`);
          }
        }
        break;
      case "agent_end":
        log(ticketId, `🏁 Agent completed`);
        break;
    }
  };
  rpc.onEvent(handleRpcEvent);

