  let beat = 0;
  const heartbeatTimer = setInterval(() => {
    beat++;
    log(ticketId, `[${new Date().toISOString()}] ⏳ Working... (${beat * 15}s elapsed)`);
    writeHeartbeat(ticketId);
  }, 15000);
