  console.log(`[kanban] Running ${lane} for ticket ${ticketId} (orchestrator: ${orchestratorModel}, subagent: ${modelStr})`);
  log(ticketId, `[${new Date().toISOString()}] 🤖 Starting ${lane} phase`);
  log(ticketId, `    Orchestrator: ${orchestratorModel}`);
  log(ticketId, `    Phase model: ${modelStr}`);

  // Ensure the ticket's clone exists (recover from remote if needed)
  if (!existsSync(ticketCloneDir(ticketId))) {
    log(ticketId, `[git] Clone missing — attempting recovery for ${ticket.branch}...`);
    const recovered = await ensureClone(ticket, project);
    if (!recovered) {
      log(ticketId, `[git] Clone recovery failed — cannot proceed with ${lane} phase`);
      return;
    }
  }
  const workDir = ticketCloneDir(ticketId);

  // Spawn the orchestrator via RpcClient — retried on transient failures
  const buildRpc = () =>
    new RpcClient({
      cwd: workDir,
      cliPath,
      env: {
        ...(process.env as Record<string, string>),
        PI_CODING_AGENT_DIR: resolve(homedir(), ".pi", "agent"),
      },
      model: orchestratorModel,
      args: ["--skill", skillPath, "--no-session"],
    });

  let rpc = buildRpc();
  let finalAssistantText = "";
  let subagentOutput = "";
  let subagentError = false;

  // Named so it can be re-registered on retry
  const handleRpcEvent = (event: any) => {
    switch (event.type) {
      case "agent_start":
