        break;
      case "turn_start":
        log(ticketId, `↻  Turn start`);
        break;
      case "tool_execution_start":
        log(ticketId, `⚙️  Calling tool: ${event.toolName}`);
        if (event.toolName === "subagent" && event.args) {
          const m = event.args.model || event.args.agent || "";
          const task = event.args.task || "";
          if (m) log(ticketId, `    subagent model: ${m}`);
          if (task) log(ticketId, `    task: ${task.slice(0, 300)}`);
        }
