/**
 * Board state module — types, persistence, helpers.
 *
 * Singleton in-memory cache backed by atomic JSON writes to state/board.json.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, renameSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { randomBytes } from "node:crypto";

// ─── Types ────────────────────────────────────────────────────────────────

/** Lane identifiers. Order here = board display order. */
export type Lane = "backlog" | "plan" | "in_progress" | "review" | "done";

export const LANES: Lane[] = ["backlog", "plan", "in_progress", "review", "done"];

/** Ticket status indicator (for UI pill). */
export type TicketStatus = "idle" | "running" | "blocked" | "done";

/** A single phase a ticket went through */
export interface CurrentPhase {
  lane: Lane;
  phaseRunId: string | null;  // null = intent (decided but not yet started)
  startedAt: number | null;    // null = intent; set when the phase actually starts
}

export interface PhaseEntry {
  phase: Lane;
  model: string;            // provider/model id used for this phase
  startedAt: number;
  endedAt: number | null;
  notes: string;            // subagent summary / test output / review findings
  findings: string[];       // structured review/test findings (if any)
  success: boolean | null;  // null = in-flight, true = passed, false = failed
}

export interface Ticket {
  id: string;
  title: string;
  description: string;
  projectId: string;
  branch: string;               // e.g. ticket/add-login-3f2a
  prUrl: string | null;
  lane: Lane;
  planFeedback: string | null;  // user comments on plan — re-runs plan phase
  status: TicketStatus;
  skipReview: boolean;          // user opted out of review phase
  reviewCycle: number;          // how many Review loops so far (cap safety)
  cancelled: boolean;           // user cancelled via delete button
  merged: boolean;              // PR has been merged on GitHub
  usePlannotator: boolean;      // use Plannotator for planning instead of subagent
  autoMerge: boolean;           // skip PR, merge branch to main, set merge-commit link
  planUrl: string | null;       // Plannotator URL when active
  currentPhase: CurrentPhase | null;  // on-disk record of what phase should be running
  createdAt: number;
  updatedAt: number;
  history: PhaseEntry[];

  // ── Orchestrator / child ticket fields ──
  orchestratorMode?: boolean;   // high-level ticket that spawns child tickets
  autoApprove?: boolean;        // auto-approve plan transitions (used for child tickets)
  parentId?: string;            // for child tickets — ID of the orchestrator parent
  childIds?: string[];          // for orchestrator parent — IDs of spawned child tickets
  orchestratorQuestions?: string; // questions asked by orchestrator during plan
}

export interface ProjectConfig {
  id: string;
  name: string;           // display name
  path: string;           // absolute or ~-expanded repo path
  defaultBranch: string;  // usually "main"
  color: string;          // hex color for UI indicators
  remoteUrl?: string;      // cached remote.origin.url — populated on add, fallback for clone
}

/** Default color palette auto-assigned to new projects. */
export const DEFAULT_PROJECT_COLORS = [
  "#7c5cfc", // purple
  "#53d8fb", // cyan
  "#2ecc71", // green
  "#e74c5c", // red
  "#f39c12", // orange
  "#a855f7", // magenta
  "#ec4899", // pink
  "#14b8a6", // teal
  "#f97316", // dark orange
  "#6366f1", // indigo
  "#84cc16", // lime
  "#06b6d4", // bright cyan
];

export interface ModelRef {
  provider: string;
  modelId: string;
}

export interface LaneModels {
  orchestrator: ModelRef;
  plan: ModelRef;
  in_progress: ModelRef;
  review: ModelRef;
}

export interface BoardState {
  projects: ProjectConfig[];
  laneModels: LaneModels;
  tickets: Ticket[];
  repoScanRoot?: string;
}

// ─── Defaults ─────────────────────────────────────────────────────────────

function envModel(key: string, fallbackProvider: string, fallbackId: string): ModelRef {
  const raw = process.env[key];
  if (raw) {
    const parts = raw.split("/");
    return parts.length >= 2
      ? { provider: parts[0], modelId: parts.slice(1).join("/") }
      : { provider: fallbackProvider, modelId: raw };
  }
  return { provider: fallbackProvider, modelId: fallbackId };
}

function defaultLaneModels(): LaneModels {
  return {
    orchestrator: envModel("KANBAN_ORCHESTRATOR_MODEL", "opencode-go", "deepseek-v4-flash"),
    plan: envModel("KANBAN_PLAN_MODEL", "opencode-go", "glm-5.2"),
    in_progress: envModel("KANBAN_CODE_MODEL", "opencode-go", "deepseek-v4-flash"),
    review: envModel("KANBAN_REVIEW_MODEL", "opencode-go", "glm-5.2"),
  };
}

export function emptyBoardState(): BoardState {
  return {
    projects: [],
    laneModels: defaultLaneModels(),
    tickets: [],
  };
}

// ─── Persistence ──────────────────────────────────────────────────────────

const scriptDir = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(scriptDir, "..");
const STATE_DIR = resolve(REPO_ROOT, "state");
const STATE_FILE = resolve(STATE_DIR, "board.json");

let cached: BoardState | null = null;

function ensureStateDir() {
  if (!existsSync(STATE_DIR)) {
    mkdirSync(STATE_DIR, { recursive: true });
  }
}

function atomicWrite(filePath: string, data: string) {
  // Write temp file in the SAME directory so renameSync stays on one fs.
  // On Linux, /tmp is often a separate tmpfs and cross-fs rename fails.
  const dir = dirname(filePath);
  const tmp = resolve(dir, `.board-${randomBytes(4).toString("hex")}.json.tmp`);
  writeFileSync(tmp, data, "utf-8");
  renameSync(tmp, filePath);
}

export function loadState(): BoardState {
  if (cached) return cached;
  ensureStateDir();
  if (!existsSync(STATE_FILE)) {
    cached = emptyBoardState();
    saveStateSync(cached);
    return cached;
  }
  try {
    const raw = readFileSync(STATE_FILE, "utf-8");
    const parsed = JSON.parse(raw) as BoardState;
    // Merge with defaults to handle schema migrations gracefully
    const projects = (parsed.projects ?? []).map((p, i) => {
      // Assign default color to legacy projects that lack one
      if (!p.color) {
        return { ...p, color: DEFAULT_PROJECT_COLORS[i % DEFAULT_PROJECT_COLORS.length] };
      }
      return p;
    });
    cached = {
      projects,
      laneModels: { ...defaultLaneModels(), ...(parsed.laneModels ?? {}) },
      tickets: parsed.tickets ?? [],
      repoScanRoot: parsed.repoScanRoot,
    };
    return cached;
  } catch {
    cached = emptyBoardState();
    saveStateSync(cached);
    return cached;
  }
}

